\displaystyle{\begin{aligned}
  \frac{{\frac{1}{r+2}+\frac{2}{r-2}}}{{1-\frac{1}{r-2}}} \amp = \frac{({\frac{1}{r+2}+\frac{2}{r-2}})\cdot{\left(r+2\right)\mathopen{}\left(r-2\right)}}{({1-\frac{1}{r-2}})\cdot{\left(r+2\right)\mathopen{}\left(r-2\right)}} \\
    \amp = \frac{{\frac{1}{r+2}\mathopen{}\left(r+2\right)\mathopen{}\left(r-2\right)+\frac{2}{r-2}\mathopen{}\left(r+2\right)\mathopen{}\left(r-2\right)}}{{\left(r+2\right)\mathopen{}\left(r-2\right)-\frac{1}{r-2}\mathopen{}\left(r+2\right)\mathopen{}\left(r-2\right)}} \\
    \amp = \frac{{r-2+2\mathopen{}\left(r+2\right)}}{{r^{2}-4-\left(r+2\right)}}, r \ne 2 \text{ and }  r \ne -2 \\
    \amp = \frac{{r-2+2r+4}}{{r^{2}-4-r-2}}, r \ne 2 \text{ and }  r \ne -2 \\
    \amp = \frac{{3r+2}}{{r^{2}-r-6}}, r \ne 2 \text{ and }  r \ne -2 \\
    \amp = {\frac{3r+2}{\left(r-3\right)\mathopen{}\left(r+2\right)}, r\ne 2}
\end{aligned}
    }
